import React from 'react';
import {User, OpenIDConnect} from 'react-oidc';

class App extends User {
    constructor(props) {
        super(props);
        
        this.configuration = {
            authority: 'https://yourauthority',
            client_id: 'yourclientid',
            redirect_uri: 'http://localhost:3000/callback',
            response_type: "code",
            scope: "openid profile email" 
        };
        
        this.signinRedirect = this.signinRedirect.bind(this);
    }
    
    signinRedirect() {
        OpenIDConnect.signIn();
    }
  
    render() {
        return (
            <div>
                <button onClick={this.signinRedirect}>Login</button>
                {/* Your application's content */}
            </div>
        );
    }
}